import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer';
import { OpenAvatarEditorParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/OpenAvatarEditorParser';

export class OpenAvatarEditorEvent
    extends MessageEvent
    implements IMessageEvent
{
    constructor(callback: (event: OpenAvatarEditorEvent) => void) {
        super(callback, OpenAvatarEditorParser);
    }

    public getParser(): OpenAvatarEditorParser {
        return this.parser as OpenAvatarEditorParser;
    }
}
